var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"말도 안 돼! 정말로 3종 침식체를 쓰러트렸잖아!","JPN":"まじかよ！　本当に第3種侵食体を倒したぞ！","ENG":"No way!! They just defeated a Category 3 C.O.!","TWN":"天啊！她們真的打敗了3類侵蝕體！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"너 저 사람들이 누군지 몰라? 크로스로드의 영웅들이잖아! 이 정도는 당연하지!","JPN":"お前あの方たちのことを知らないのか？　クロスロードの英雄なんだ！　これくらい当たり前さ！","ENG":"Of course, they did! They're the heroes of Crossroads! That's a cinch for them!","TWN":"你不認識她們嗎？那可是十字路口作戰的英雄！這是正常發揮吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아! 다들 조금만 힘내자!","JPN":"よし！　みんなもう少し頑張るぞ！","ENG":"All right! Let's all push through!","TWN":"很好！大家再加把勁兒！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"자자, 어서 보급품이랑 부상자들부터 함선으로 옮기자고!","JPN":"さあさあ、早く補給品と負傷者を艦船に運ぼうぜ！","ENG":"Okay, let's move the supplies and the injured into the ship!","TWN":"來，快點先把補給品和傷患都轉移到艦船！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아야야, 허리야~ 설마 진짜로 던져버릴 줄은 몰랐는데~","JPN":"いててて、腰が～、まさか本当に投げ飛ばされるとはね～","ENG":"Ow... My back...! Didn't think you'd really throw me off the ship...","TWN":"哎呀呀，我的腰啊~居然真的把我扔下來～"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무리 우리 사이가 각별해도 이런 장난은 너무 심한 거…… ","JPN":"さすがの私たちの仲でも、この悪戯はちょっと酷いんじゃ…… ","ENG":"I mean, I know we're close, but that prank was a little too harsh–","TWN":"就算我們不是普通關係，這玩笑也開得太過分……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"음? 카린 양?","JPN":"ん？　カリンさん？","ENG":"Hmm? Karin?","TWN":"嗯？卡琳？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"하아…… 하아……","JPN":"はぁ……はぁ……","ENG":"*Huff*... *Huff*...","TWN":"唔唔，哈啊……哈啊……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"진통제 쏴 줄 테니까 조금만 참아, 앨런!","JPN":"鎮痛剤を打つからもう少しだけ耐えるんだぞ、アラン！","ENG":"Allan, hang in there! I'll be right over with your painkillers!","TWN":"這裡有鎮痛劑，再忍一忍，艾倫！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"그깟 상처쯤 약 좀 바르고, 살 좀 꿰매면 금방 나을 거야!","JPN":"そんなケガぐらい、薬塗って、ちょっと縫えばすぐに良くなるさ！","ENG":"You'll be good as new after some ointment and stitches!","TWN":"這點傷抹下藥，縫合一下很快就能好！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"하, 하하 뻥 좀 치지 마. 이 멍청이들아.","JPN":"は、はは、嘘はやめろよ。馬鹿が。","ENG":"Ha... ha ha! You idiots. Don't lie to me.","TWN":"哈，哈哈！少騙人了。你們這些傻瓜。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"뚫린 구멍으로 내 뱃속이 훤히 보이는데, 약 바른다고 이게 살겠냐. 제기랄.","JPN":"貫通した穴から自分の腹の中が丸見えなんだ、薬を塗ったところで助かるわけがないだろ。くそっ。","ENG":"I can see right through the hole in my stomach. Some ointment and stitches ain't fixin' that. Dammit.","TWN":"從傷口的洞都能看到我的五臟六腑了，光擦藥能治好？胡說八道。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대원, 이름과 소속을.","JPN":"隊員、名前と所属は。","ENG":"You there. Name and affiliation.","TWN":"隊員，報上你的姓名和所屬。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"앨런 베이커, 3지구 소속입니다.","JPN":"アラン・ベーカー、第3地区所属です。","ENG":"Allan Baker. 3rd District, ma'am.","TWN":"艾倫·貝克，隸屬第三區。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"하하. 젠장, 이런 못 볼 꼴 보여서…… 죄송합니다. 소령님.","JPN":"はは。くそ、こんなみっともない姿を晒して……本当に申し訳ありません。少佐。","ENG":"Ha ha. Damn... I'm sorry you had to see this, Major.","TWN":"唔，可惡，讓你看到如此不堪的一面……非常抱歉，少校。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"크로스로드의 영웅과 함께 싸울 수 있는 기회였는데, 이걸……","JPN":"クロスロードの英雄たちと一緒に戦えるチャンスだったのにな、よりによって……","ENG":"This was my chance to fight alongside the heroes of Crossroads...","TWN":"好不容易能有和十字路口的英雄一起並肩作戰的機會，我卻……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":" 쿨럭!?","JPN":" ガハッ！？","ENG":"Kuh?!","TWN":"咳咳？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GUARD_EXILER_NPC_A","text":{"KOREA":"그래도 마지막에는…… 이런 미인인 소령님이…….","JPN":"でも死ぬ直前に……こんな美人の少佐が……","ENG":"But at the very least... I got to see the beautiful major...","TWN":"不過，至少最後……能見到美麗的少校……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GUARD_EXILER_NPC_B","text":{"KOREA":"앨런! 앨런! 임마! 정신 차려, 정신 차리라고!!!","JPN":"アラン！　アラン！　おい！　しっかり、しっかりしろ！！！","ENG":"Allan? ALLAN! Hey! Wake up! WAKE UP!!!","TWN":"艾倫！艾倫！喂！振作一點，醒一醒！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GUARD_EXILER_NPC_C","text":{"KOREA":"포기해, 이미 죽었어.","JPN":"諦めろ、もう死んでいる。","ENG":"Enough, he's already dead.","TWN":"放棄吧……他已經死了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_C","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"앨런 대원.","JPN":"アラン隊員。","ENG":"Allan Baker.","TWN":"艾倫隊員。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는, 그리고 우리는 군을 대표해서 당신의 이름과 희생을 잊지 않겠습니다.","JPN":"私は、そして私たちは軍を代表してあなたの名前と犠牲を決して忘れません。","ENG":"As a representative of our armed forces, I will never forget your name or your valiant service.","TWN":"我，以及我們，會代表軍方紀念你的名字和犧牲。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니 앞서 가시는 길. 부디 평안하길.","JPN":"ですから、安らかにお眠りください。","ENG":"So, may you rest in peace.","TWN":"願你一路走好。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저, 카린 양?","JPN":"あの、カリンさん？","ENG":"Um, Karin?","TWN":"那個，卡琳？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"잠깐 시간 좀 내줄 수 있어요? 이야기 좀 하고 싶은데.","JPN":"少しいいですか？　お話したいことがあるんですけど。","ENG":"Do you have a moment? I have something I want to talk about.","TWN":"能佔用你點時間嗎？我有話想跟你說。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐죠? 아직 정리할 물자가 남아서.","JPN":"何ですか？　まだ片付け終わっていない物資があるので。","ENG":"What is it? I still have some supplies to organize.","TWN":"什麼事？我還需要整理物資。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"안 돼요, 안 돼!","JPN":"ダメです、ダメ！","ENG":"No, NO!","TWN":"欸？欸欸——？什麼嘛！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"요즘 카린 양 너무 저한테 너무 소홀한걸요!","JPN":"最近、カリンさんは私をほったらかしにしすぎです！","ENG":"You haven't been giving me enough attention these days!","TWN":"最近卡琳對我太冷淡了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저, 외롭다고요? 바람피울 거라고요?","JPN":"私、寂しいんですよ？　浮気しちゃいますよ？","ENG":"I'm lonely, okay? And I might just cheat on you!","TWN":"我可是很寂寞的欸？再這樣下去，小心我出軌喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"누, 누가 들으면 오해할 소리 좀 하지 마세요! 진짜!","JPN":"ちょっと、変に誤解されるような言い方はやめてください！　もう！","ENG":"S-stop saying that, people might misunderstand you!","TWN":"不，不要說會讓別人誤會的話！真是的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서 할 얘기라는 게 뭔데요?","JPN":"それで、話したいこととは何なんですか？","ENG":"So? What is it that you wanted to talk about?","TWN":"所以呢，你要說什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"으헷! 시, 시영 씨! 간지럽게 무슨 짓이에요!","JPN":"きゃっ！　し、シノンさん！　急に何ですか、くすぐったいですよ！","ENG":"Eek! S-Shiyoung! That tickles!","TWN":"哈哈！時，時雨！這樣子很癢！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"왜 갑자기 어깨를 주무르고 난리야!","JPN":"急にどうして肩を揉むんですか！","ENG":"Why are you massaging my shoulders all of a sudden?","TWN":"為什麼突然捏我肩膀！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후. 그치만 카린 양, 어깨에 힘이 너무 많이 들어가 있는 걸요?","JPN":"ふふ。だってカリンさん、肩に力が入りすぎですよ？","ENG":"Heh heh. But Karin, your shoulders are soooo stiff.","TWN":"嘿嘿，卡琳，你的肩上承擔著太多的壓力啦！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼意思？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐, 델타 세븐의 마지막 대원으로서, 지휘관으로서, 어깨가 무겁다는 건 알겠지만……","JPN":"まぁ、デルタセブンの最後の隊員として、指揮官として、肩の荷が思いのはわかりますけど……","ENG":"Well, I get it. You have a lot on your shoulders as the last member of Delta Seven and its commander, but...","TWN":"我能理解你作為第七三角洲部隊僅剩的隊員，和身為指揮官肩負重擔……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇다고 그렇게 뭐든 전부 짊어지려고 하면, 언젠가 콱! 무너져 버릴지도 모른다고요.","JPN":"だからといって何でもかんでも一人で背負おうとすると、どこかでぶちっと糸が切れちゃうかもしれませんよ。","ENG":"But if you keep burdening yourself and taking responsibility for everything, then one day! You're going to collapse.","TWN":"但什麼都往自己肩上扛的話，總有一天會不堪重負的喔。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무튼! 요점은 너무 앞만 바라보지 말고, 가끔은 이쪽도 돌아봐 달라는 뜻!","JPN":"とにかく！　要するに、あまり前ばかりを見てないで、たまにはこっちにも目を向けてほしいってことなんです！","ENG":"Anyway! My point is that you should stop looking into the future and look at me for once!","TWN":"總之，我的意思是不要只顧著向前看，偶爾也回頭看看我！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"깐깐한 카린 양이지만, 의외로 카린 양 주위엔 고민을 나눌 동료가 잔뜩 있잖아요?","JPN":"気難しいカリンさんですけど、案外周りには悩みを分かち合える仲間がたくさんいるんですよ？","ENG":"I know you're a perfectionist, but just know that there are people around you who are willing to share the load.","TWN":"雖然卡琳固執又彆扭，但你的身邊還是有很多能讓你傾訴煩惱的夥伴，不是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알겠어요. 시영 씨.","JPN":"わかりました。シノンさん。","ENG":"Okay, Shiyoung.","TWN":"知道了，時雨。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇지 않아도 늘 고맙게 생각하고 있어요.","JPN":"もちろん、いつもありがたく思っています。","ENG":"Even if I don't say it, I'm grateful to have you beside me.","TWN":"其實我心裡一直很感激你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼요, 그럼요.","JPN":"ええ、そうでしょうとも。","ENG":"Of course you are.","TWN":"嗯嗯，那是當然。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저만큼이나 카린 양을 좋아하는 사람이 어디 있겠어요?","JPN":"私ほどのカリンさん想いはいませんよね？","ENG":"Who else in the world likes you more than I do, Karin?","TWN":"哪裡還能找的到像我這樣喜歡你的人呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 저 먼저 돌아갈 테니까, 카린 양도 적당히 하고 돌아오세요.","JPN":"では、私は先に帰りますから、カリンさんもあまり無理しないでくださいね。","ENG":"Well, I'm gonna head in first. I suggest that you finish up and do the same.","TWN":"那我就先回去囉，你也要早點回去喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇지만…… 시영 씨.","JPN":"ですが……シノンさん。","ENG":"But... Shiyoung.","TWN":"但是……時雨。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨가 절 어떻게 생각할지 몰라도.","JPN":"シノンさんにどう思われようと。","ENG":"I don't know what you'll think of me, Shiyoung, but...","TWN":"雖然不知道你會怎麼想。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 대령님이 그러셨던 것처럼, 반드시 이 세계를 지켜낼 거예요.","JPN":"私は大佐がされたように、必ずこの世界を守ってみせます。","ENG":"Like Colonel did, I will also protect this world no matter what.","TWN":"我想要像上校那樣，守護這個世界。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 사명을 위해서라면, 저는 어떤 것이든 짊어지겠어요.","JPN":"その使命のためなら、何であろうと背負う覚悟はできています。","ENG":"And I will do whatever it takes to accomplish my duties.","TWN":"為了那個使命，我會擔負起一切。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};